}

int psa_server_main(int argc, char *argv[])
{
    psa_status_t ret = PSA_ERROR_PROGRAMMER_ERROR;
    psa_msg_t msg = { -1 };
    const int magic_num = 66;
    int client_disconnected = 0;
    extern psa_status_t psa_crypto_call(psa_msg_t msg);
